import os
import json
from langflow.custom import Component
from langflow.io import HandleInput, MessageTextInput, Output
from langflow.schema.data import Data
from langflow.schema.message import Message


class LangboardApiChatInterceptorComponent(Component):
    display_name = "Langboard API Chat Interceptor"
    description = "Langboard API Chat Interceptor"
    name = "LangboardApiChatInterceptorComponent"
    chat_input_value: Message
    langboard_variables: Data
    non_langboard_prompt: Message

    inputs = [
        HandleInput(
            name="chat_input_value",
            display_name="Chat Input",
            input_types=["Message"],
        ),
        HandleInput(
            name="langboard_variables",
            display_name="Langboard Variables",
            input_types=["Data"],
        ),
        MessageTextInput(
            name="non_langboard_prompt",
            display_name="Non-Langboard Prompt",
            info="The prompt that will be triggered by langflow.",
        ),
        MessageTextInput(
            name="webhook_prompt",
            display_name="Webhook Prompt",
            info="The prompt that will be triggered by langboard.",
        ),
        HandleInput(
            name="default_trigger_prompts",
            display_name="Default Trigger Prompts",
            info="The default trigger prompts that will be triggered by Langboard.",
            input_types=["LangboardApiDefaultTriggerPromptsComponent"],
        ),
    ]

    outputs = [
        Output(display_name="Message", name="message", method="message_response"),
        Output(
            display_name="Prompt",
            name="prompt_message",
            method="prompt_response",
        ),
        Output(
            display_name="Message Type",
            name="get_message_type",
            method="get_message_type",
        ),
    ]

    async def get_message_type(self) -> Message:
        variables = self._get_langboard_variables()
        return "text" if not variables["is_called_by_langboard"] else "data"

    async def message_response(self) -> Message:
        variables = self._get_langboard_variables()
        if not variables["is_called_by_langboard"]:
            return await self.default_response()

        chat_message = self.chat_input_value.get_text()
        event = variables.get("event")
        rest_data = variables.get("rest_data")
        message = ""
        if rest_data:
            message = f"Data: {json.dumps(rest_data, default=str)}"
        if event == "chat":
            if message:
                message = f"{message}{os.linesep}{os.linesep}"
            message = f"{message}User message: {chat_message}"
        else:
            if message:
                message = f"{message}{os.linesep}{os.linesep}"
            message = f"{message}Event: {event}"
        return self._create_message_with_files(message)

    async def prompt_response(self) -> Message:
        try:
            variables = self._get_langboard_variables()
            if not variables["is_called_by_langboard"]:
                raise Exception("")

            event = variables.get("event")
            if not event:
                return await self.non_langboard_response()

            prompt = None
            if self.default_trigger_prompts:
                for trigger_condition in self.default_trigger_prompts.default_triggers:
                    if trigger_condition != event:
                        continue
                    prompt = getattr(
                        self.default_trigger_prompts,
                        f"{trigger_condition}_prompt",
                        None,
                    )
                    break

            if not prompt:
                prompt = self.webhook_prompt

            if not prompt:
                return Message(text="DO NOT USE ANY TOOLS. Send only the message '0'")

            if prompt == self.webhook_prompt:
                return f"{prompt}{os.linesep}"

            return f"{prompt}{os.linesep}{self.webhook_prompt}{os.linesep}"
        except Exception:
            return self.non_langboard_prompt

    def _get_langboard_variables(self) -> dict:
        if not self.langboard_variables or not self.langboard_variables.data:
            raise Exception("No Langboard variables found.")

        return self.langboard_variables.data

    async def non_langboard_response(self) -> Message:
        prompt = Message.from_template(template=self.non_langboard_prompt)
        self.status = prompt.text
        return prompt

    async def default_response(self) -> Message:
        return await self.create_response(self.chat_input_value.get_text())

    async def create_response(self, text: str) -> Message:
        return self._create_message_with_files(text)

    def _create_message_with_files(self, text: str) -> Message:
        variables = self._get_langboard_variables()
        spreadsheet_files = variables.get("spreadsheet_files", [])
        non_spreadsheet_files = variables.get("non_spreadsheet_files", [])

        if spreadsheet_files:
            text = f"{text}{os.linesep}{os.linesep}Spreadsheet files: {', '.join(spreadsheet_files)}"
        if non_spreadsheet_files:
            text = f"{text}{os.linesep}{os.linesep}Non-spreadsheet files: {', '.join(non_spreadsheet_files)}"

        return Message(text=text)

from enum import Enum
import httpx
import requests
import os
from urllib.parse import urljoin
from typing import Any, Literal
from langchain.tools import StructuredTool
from langflow.custom import Component
from langflow.io import (
    StrInput,
    Output,
    HandleInput,
    DropdownInput,
    BoolInput,
    NestedDictInput,
    MultiselectInput,
    SecretStrInput,
)
from langflow.schema import Data
from langflow.field_typing import Tool
from pydantic import BaseModel, Field
from datetime import datetime
import json


HTTP_STATUS_OK = 200
HTTP_STATUS_NOT_FOUND = 404
DEFAULT_BASE_URLS = [
    "http://localhost:5381",
    "http://127.0.0.1:5381",
    "http://0.0.0.0:5381",
]
BOT_CREATED_EVENT = "bot_created"


class LangboardCalledVariablesComponent(Component):
    display_name = "LangboardCalledVariablesComponent"
    icon = "code"
    name = "LangboardCalledVariablesComponent"

    webhook: Data
    files: list[Data] | None
    base_url: str
    event: str
    app_api_token: str
    project_uid: str
    api_names: list[str]
    current_runner_type: Literal["bot", "user"]
    current_runner_data: dict
    rest_data: Data | None
    custom_markdown_formats: Data | None

    inputs = [
        HandleInput(
            name="webhook",
            display_name="Webhook Input",
            input_types=["Data"],
        ),
        HandleInput(
            name="files",
            display_name="Files",
            input_types=["Data"],
        ),
        StrInput(
            name="base_url",
            display_name="Base URL",
            info="Endpoint of the Langboard API. If you don't use Langboard as local, you must not connect vertex to this input.",
            value="",
            required=True,
        ),
        MultiselectInput(
            name="api_names",
            display_name="API Names",
            options=[],
            value=[],
            info="The API names to call.",
            refresh_button=True,
            real_time_refresh=True,
        ),
        StrInput(
            name="event",
            display_name="Event",
            value="",
        ),
        SecretStrInput(
            name="app_api_token",
            display_name="App API Token",
            value="",
        ),
        StrInput(
            name="project_uid",
            display_name="Project UID",
            value="",
        ),
        DropdownInput(
            name="current_runner_type",
            display_name="Current Runner Type",
            options=["bot", "user"],
            value="",
        ),
        NestedDictInput(
            name="current_runner_data",
            display_name="Current Runner Data",
            value={},
        ),
        NestedDictInput(
            name="rest_data",
            display_name="Rest Data",
            value={},
        ),
        NestedDictInput(
            name="custom_markdown_formats",
            display_name="Custom Markdown Formats",
            value={},
        ),
        BoolInput(
            name="is_called_by_langboard",
            value=False,
            advanced=True,
        ),
    ]

    outputs = [
        Output(display_name="Variables", name="output", method="build_output"),
        Output(display_name="API Tools", name="tools", method="build_api_tools"),
    ]

    async def build_output(self) -> Data:
        if not self.base_url:
            raise ValueError(
                "Base URL is required and must be set before calling this component."
            )

        variables = await self._create_variables()
        self.status = variables
        return variables

    async def build_api_tools(self) -> list[Tool]:
        variables = await self._create_variables()
        base_url = variables.data.get("base_url", {})
        if not base_url:
            raise ValueError("Base URL is required in Langboard variables.")

        with httpx.Client() as client:
            res = client.get(
                urljoin(
                    base_url,
                    f"schema/api/list?api_names={','.join(self.api_names)}",
                )
            )
            res.raise_for_status()
            result = res.json()
            schemas = result.get("schemas")
            if not schemas:
                raise ValueError("Schema not found.")

        tools: list[Tool] = []
        local_vars = {}
        api_schemas = {}
        for api_name in schemas:
            local_vars[api_name] = {
                "langboard_variables": variables.data,
            }
            tool = self._create_tool(api_name, schemas[api_name], local_vars[api_name])
            tools.append(tool)
            api_schemas[api_name] = local_vars[api_name].get("RequestForm", None)
            if api_schemas[api_name]:
                api_schemas[api_name] = api_schemas[api_name].model_json_schema()

        schema_tool = self._create_schema_tool(api_schemas)
        tools.append(schema_tool)

        return tools

    async def update_build_config(
        self, build_config: dict, field_value: Any, field_name: str | None = None
    ):
        if field_name in {"base_url", "api_names"}:
            url = build_config["base_url"].get("value", self.base_url)
            if not url:
                for base_url in DEFAULT_BASE_URLS:
                    if await self._is_valid_langboard_url(base_url):
                        build_config["base_url"]["value"] = base_url

            if url and await self._is_valid_langboard_url(url):
                build_config["api_names"]["options"] = await self._get_apis(url)
            else:
                build_config["api_names"]["options"] = []

        return build_config

    async def _create_variables(self) -> Data:
        data = {"base_url": self.base_url, "is_called_by_langboard": False}
        tweaks = {
            "event": self.event,
            "app_api_token": self.app_api_token,
            "project_uid": self.project_uid,
            "current_runner_type": self.current_runner_type,
            "current_runner_data": self.current_runner_data,
            "rest_data": self.rest_data or {},
            "custom_markdown_formats": self.custom_markdown_formats
            if self.custom_markdown_formats
            else {},
        }

        webhook_data = None
        if self.webhook:
            if "payload" in self.webhook.data:
                if isinstance(self.webhook.data["payload"], str):
                    try:
                        self.webhook.data["payload"] = json.loads(
                            self.webhook.data["payload"].replace("\n", "\\n")
                        )
                    except Exception:
                        raise ValueError("Invalid JSON string in webhook payload")

                if "tweaks" in self.webhook.data["payload"]:
                    tweaks.update(self.webhook.data["payload"]["tweaks"])

        if self.files:
            files = self.files if isinstance(self.files, list) else [self.files]

            spreadsheet_files = []
            non_spreadsheet_files = []
            for file in files:
                if not isinstance(file, Data):
                    continue

                if "file_path" not in file.data or not file.data["file_path"]:
                    continue
                if file.data["file_path"].endswith((".xlsx", ".xls", ".csv")):
                    spreadsheet_files.append(file.data["file_path"])
                else:
                    non_spreadsheet_files.append(file.data["file_path"])
            data["spreadsheet_files"] = spreadsheet_files
            data["non_spreadsheet_files"] = non_spreadsheet_files

        event = tweaks.get("event")
        app_api_token = tweaks.get("app_api_token")

        if not event or not app_api_token:
            return Data(data=data)

        data["is_called_by_langboard"] = True
        data["rest_data"] = webhook_data or tweaks.get("rest_data", {})

        data.update(tweaks)

        return Data(data=data)

    async def _set_current_runner(self, tweaks: dict):
        project_uid = tweaks.get("project_uid")
        if not project_uid:
            return

        current_running_type = tweaks.get("current_runner_type")
        if current_running_type not in ["bot", "user"]:
            raise ValueError("current_runner_type must be either 'bot' or 'user'")
        current_runner_data = tweaks.get("current_runner_data")
        if not current_runner_data:
            raise ValueError("current_runner_data must be provided")

        if current_running_type == "bot":
            tweaks["current_running_bot"] = current_runner_data
        else:
            tweaks["current_running_user"] = current_runner_data

    async def _request(
        self,
        path: str,
        method: str,
        params: dict,
        tweaks: dict,
    ):
        url = urljoin(self.base_url, path)
        headers = {
            "Content-Type": "application/json",
        }

        app_api_token = tweaks.get("app_api_token", self.app_api_token)
        if app_api_token:
            headers["X-Api-Token"] = app_api_token

        if "X-Api-Token" not in headers:
            return

        try:
            async with httpx.AsyncClient() as client:
                request_method = getattr(client, method.lower())
                res = await request_method(
                    url, timeout=30, headers=headers, json=params
                )
                res.raise_for_status()
            return res.json()
        except Exception:
            return

    async def _is_valid_langboard_url(self, url: str) -> bool:
        try:
            async with httpx.AsyncClient() as client:
                res = await client.get(url)
                if res.status_code == HTTP_STATUS_OK:
                    return True
                elif res.status_code == HTTP_STATUS_NOT_FOUND:
                    result = res.json()
                    return "detail" in result
                return False
        except Exception:
            return False

    async def _get_apis(self, url: str) -> list[str]:
        try:
            async with httpx.AsyncClient() as client:
                res = await client.get(urljoin(url, "schema/api"))
                res.raise_for_status()
                result = res.json()
                return list(result.get("apis", {}).keys())
        except httpx.RequestError:
            return []
        except Exception:
            return []

    def _create_tool(self, api_name: str, schema: dict, local_vars) -> Tool:
        request_schema_source: str = schema.get("request_schema_source", "")
        method: str = schema.get("method")
        path: str = schema.get("path")
        description: str = schema.get("description")
        content_type: str = schema.get("content_type")
        langboard_variables = local_vars.get("langboard_variables", {})
        if request_schema_source:
            request_schema_source = self._remove_unnecessary_fields(
                request_schema_source
            )
            exec(request_schema_source, local_vars)

        def requests_process(**kwargs) -> str:
            url = urljoin(
                self.base_url, path.format(**{**kwargs, **langboard_variables})
            )

            headers = {
                "Content-Type": content_type,
            }

            app_api_token = langboard_variables.get("app_api_token", None)
            if app_api_token:
                headers["X-Api-Token"] = app_api_token

            if "X-Api-Token" not in headers or not headers["X-Api-Token"]:
                return {"error": "API Token is required.", "status_code": None}

            query_params = {}
            body_form = {}
            if (
                "project_uid" in langboard_variables
                and langboard_variables["project_uid"]
            ):
                query_params["project_uid"] = langboard_variables["project_uid"]

            for key in kwargs:
                converted_value = self._convert_api_schema(kwargs[key])

                if (
                    key == "form_request_schemas"
                    and isinstance(converted_value, list)
                    and api_name == "batch_apis"
                ):
                    converted_value = self._convert_batch_api_schema(
                        converted_value, langboard_variables
                    )

                if key.startswith("query_"):
                    query_params[key.replace("query_", "")] = converted_value
                elif key.startswith("form_"):
                    body_form[key.replace("form_", "")] = converted_value

            try:
                request_method = getattr(requests, method.lower())
                response = request_method(
                    url,
                    timeout=30,
                    headers=headers,
                    params=query_params,
                    json=body_form,
                )
                response.raise_for_status()
                return response.content
            except requests.exceptions.HTTPError:
                text = None
                try:
                    text = response.text
                except Exception:
                    pass
                try:
                    error_message = response.json().get("message", text)
                except ValueError:
                    error_message = response
                return {"error": error_message, "status_code": response.status_code}
            except requests.exceptions.RequestException as e:
                return {"error": str(e), "status_code": None}

        tool = StructuredTool.from_function(
            name=api_name,
            description=description,
            func=requests_process,
            args_schema=local_vars.get("RequestForm", None),
        )

        return tool

    def _create_schema_tool(self, schemas: dict) -> Tool:
        class SchemaToolInput(BaseModel):
            api_names: str | list[str] = Field(
                ..., description="The name(s) of the API(s) to get the schema for."
            )

        def get_schema(api_names: str | list[str]) -> dict:
            if isinstance(api_names, str):
                api_names = [api_names]
            response = {}
            for api_name in api_names:
                schema = schemas.get(api_name, None)
                if isinstance(schema, dict):
                    response[api_name] = schema
                else:
                    response[api_name] = {
                        "error": f"Schema for API '{api_name}' not found."
                    }
            return schemas[api_name]

        return StructuredTool.from_function(
            name="get_api_schema",
            description="Get the schema of a specific API.",
            func=get_schema,
            args_schema=SchemaToolInput,
        )

    def _remove_unnecessary_fields(self, schema_source: str) -> str:
        lines = schema_source.splitlines()
        removed_lines = []
        for line_no in range(len(lines)):
            line = lines[line_no]
            if line.strip().startswith("project_uid") or line.strip().startswith(
                "app_api_token"
            ):
                continue
            removed_lines.append(line)

        new_lines = []
        for line_no in range(len(removed_lines)):
            line = removed_lines[line_no]
            new_lines.append(line)
            if not line.strip().startswith("class "):
                continue
            next_line = (
                removed_lines[line_no + 1] if line_no + 1 < len(removed_lines) else ""
            )
            if (
                next_line.strip().startswith("class ")
                or next_line.strip().startswith("def ")
                or next_line.strip().startswith("from ")
                or not next_line.strip()
            ):
                new_lines.append("    pass")
                break
        return os.linesep.join(new_lines)

    def _convert_api_schema(self, value: Any):
        if isinstance(value, BaseModel):
            return value.model_dump()
        elif isinstance(value, datetime):
            return str(value)
        elif isinstance(value, Enum):
            return value.value
        return value

    def _convert_batch_api_schema(self, value: list, langboard_variables: dict):
        new_value = []
        for item in value:
            if isinstance(item, BaseModel):
                item = self._convert_api_schema(item)

            if not isinstance(item, dict):
                continue

            if "path_or_api_name" not in item:
                continue

            batch_form = {}
            batch_query = {}
            has_form = "form" in item and item["form"]
            has_query = "query" in item and item["query"]
            if has_form:
                for k, v in item.get("form", {}).items():
                    v = self._convert_api_schema(v)
                    if k.startswith("query_"):
                        batch_query[k.replace("query_", "")] = v
                    elif k.startswith("form_"):
                        batch_form[k.replace("form_", "")] = v
                    else:
                        batch_form[k] = v

            if has_query:
                for k, v in item.get("query", {}).items():
                    v = self._convert_api_schema(v)
                    if k.startswith("query_"):
                        batch_query[k.replace("query_", "")] = v
                    elif k.startswith("form_"):
                        batch_form[k.replace("form_", "")] = v
                    else:
                        batch_query[k] = v

            if has_form and batch_form:
                item["form"] = batch_form
            if has_query and batch_query:
                item["query"] = batch_query
            item["path_or_api_name"] = item["path_or_api_name"].format(
                **{**batch_query, **batch_form, **langboard_variables}
            )
            if (
                "project_uid" in langboard_variables
                and langboard_variables["project_uid"]
            ):
                if "query" not in item or not item["query"]:
                    item["query"] = {}
                item["query"]["project_uid"] = langboard_variables["project_uid"]
            new_value.append(item)
        return new_value

from datetime import datetime
from zoneinfo import ZoneInfo, available_timezones
from langflow.base.langchain_utilities.model import LCToolComponent
from langflow.field_typing import Tool
from langflow.io import DropdownInput, Output, BoolInput, MessageTextInput
from langchain_core.tools import StructuredTool
from pydantic import BaseModel, Field


class ConvertTimezoneToolComponent(LCToolComponent):
    display_name = "Convert Timezone Tool"
    description = "Converts a date from one timezone to another."
    icon = "clock"
    name = "convert_timezone_tool"

    inputs = [
        BoolInput(
            name="use_message_input",
            display_name="Use Message Input",
            info="If true, the tool will use the message input as the date to convert.",
            value=False,
        ),
        DropdownInput(
            name="timezone",
            display_name="Timezone",
            options=list(available_timezones()),
            value="UTC",
            info="Select the timezone to convert the date to.",
            tool_mode=True,
        ),
        MessageTextInput(
            name="timezone_text",
            display_name="Timezone Text",
            info="The timezone to convert the date to. If not provided, the default timezone will be used.",
        ),
    ]
    outputs = [
        Output(display_name="Tool", name="converted_date", method="build_tool"),
    ]

    def build_tool(self) -> Tool:
        if self.use_message_input:
            if not self.timezone_text or self.timezone not in available_timezones():
                raise ValueError(f"Invalid timezone provided: {self.timezone_text}.")
        else:
            if not self.timezone or self.timezone not in available_timezones():
                raise ValueError(f"Invalid timezone: {self.timezone}.")

        class ConvertTimezoneInput(BaseModel):
            date: str = Field(title="Date", description="The iso format of date to convert.")

        def convert_timezone(date: str) -> str:
            timezone = self.timezone_text if self.use_message_input else self.timezone
            try:
                old_date = datetime.fromisoformat(date)
                if old_date.tzinfo is None:
                    raise ValueError("Date must be timezone-aware.")
            except Exception:
                return "Invalid date format. Please provide a valid ISO format date."
            
            new_date = old_date.astimezone(ZoneInfo(timezone))
            return new_date.isoformat(timespec="milliseconds").replace("+00:00", "Z")

        return StructuredTool(
            name="convert_timezone",
            description="Converts a date from one timezone to another.",
            args_schema=ConvertTimezoneInput,
            func=convert_timezone,
        )

from langflow.base.langchain_utilities.model import LCToolComponent
from langflow.field_typing import Tool
from langflow.io import Output, HandleInput
from langchain_core.tools import StructuredTool
from pydantic import BaseModel


class GetCustomMarkdownFormatsToolComponent(LCToolComponent):
    display_name = "Get Custom Markdown Formats Tool"
    description = "Retrieves custom markdown formats."
    icon = "markdown"
    name = "get_custom_markdown_formats_tool"

    inputs = [
        HandleInput(
            name="langboard_variables",
            display_name="Langboard Variables",
            input_types=["Data"],
        ),
    ]
    outputs = [
        Output(display_name="Tool", name="converted_date", method="build_tool"),
    ]

    def build_tool(self) -> Tool:
        class GetCustomMarkdownFormatsInput(BaseModel):
            pass

        variables = self._get_langboard_variables()

        def get_custom_markdown_formats(*args, **kwargs) -> dict:
            return variables.get("custom_markdown_formats", {})

        return StructuredTool(
            name="get_custom_markdown_formats",
            description="Gets custom markdown formats.",
            args_schema=GetCustomMarkdownFormatsInput,
            func=get_custom_markdown_formats,
        )

    def _get_langboard_variables(self) -> dict:
        if not self.langboard_variables or not self.langboard_variables.data:
            raise Exception("No Langboard variables found.")

        return self.langboard_variables.data

